#include <stdio.h>
#include <string.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        char s[100005];
        scanf("%d", &N);
        scanf("%s", s);
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            if (s[i] == '1') {
                for (int j = i; j < N; ++j) {
                    if (s[j] == '1') ++ans;
                }
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

